// Built-in Suricatoos logo, pre-rasterized to clean PNGs (the meerkat-S vector is too intricate for
// react-pdf's SVG renderer and unreadable at small sizes raw). BADGE = the logo inside a white
// rounded chip — reads cleanly on both dark and light backgrounds; the default for reports.
// WHITE/BLUE are the bare marks for light/dark contexts. Whitelabel deployments override these via
// Branding.appLogo / appLogoOnDark (uploaded data URIs).
export const SURICATOOS_LOGO_BADGE = 'data:image/png;base64,';
export const SURICATOOS_LOGO_WHITE = 'data:image/png;base64,';
export const SURICATOOS_LOGO_BLUE = 'data:image/png;base64,';
